# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import json

def lambda_handler(event, context):
    # Database connection details
    rds_host = "your-rds-endpoint"
    username = "your-username"
    password = "your-password"
    db_name = "your-database-name"

    # Connect to the RDS instance
    try:
        conn = pymysql.connect(host=rds_host, user=username, passwd=password, db=db_name, connect_timeout=5)
    except pymysql.MySQLError as e:
        print(f"Error connecting to MySQL database: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps('Failed to connect to the database')
        }

    # Parse query parameters from API Gateway event
    search_params = event.get('queryStringParameters', {})
    query_conditions = []

    if 'name' in search_params:
        query_conditions.append(f"name LIKE '%{search_params['name']}%'")
    if 'category' in search_params:
        query_conditions.append(f"category = '{search_params['category']}'")
    if 'price_min' in search_params:
        query_conditions.append(f"price >= {float(search_params['price_min'])}")
    if 'price_max' in search_params:
        query_conditions.append(f"price <= {float(search_params['price_max'])}")

    # Build the SQL query dynamically
    sql_query = "SELECT * FROM products WHERE " + " AND ".join(query_conditions)

    try:
        with conn.cursor() as cur:
            cur.execute(sql_query)
            result = cur.fetchall()
            columns = [col[0] for col in cur.description]
            response_data = [dict(zip(columns, row)) for row in result]
    except pymysql.MySQLError as e:
        print(f"Error executing SQL query: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps('Failed to execute the query')
        }
    finally:
        conn.close()

    # Return the response
    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/json'
        },
        'body': json.dumps(response_data)
    }